<!-- ===== ABOUT ===== -->
<section class="about-section has-deco" id="sobre">
  <div class="deco"
    style="width:180px;top:-20px;right:-20px;--db:rotate(10deg);animation:df 11s ease-in-out 0s infinite;"><img
      src="data:image/png;base64,"
      style="opacity:0.15"></div>
  <div class="about-visual reveal">
    <div class="about-img-main">
      <img
        src="data:image/jpeg;base64,"
        alt="Q'SAMBA — Lisboa">
    </div>
    <div class="about-img-secondary">
      <img
        src="data:image/jpeg;base64,"
        alt="Q'SAMBA ao vivo">
    </div>
  </div>
  <div class="about-text reveal reveal-delay-2">
    <div class="section-label"><?= __('about.label') ?></div>
    <h2 class="section-title"><?= __('about.title') ?><br><?= __('about.title_2') ?> <span style="color:var(--pink)"><?= __('about.title_hl') ?></span></h2>
    <p><?= __('about.text') ?></p>
    <div class="about-tags">
      <span class="about-tag">🇦🇴 Angola</span>
      <span class="about-tag">🇵🇹 Portugal</span>
      <span class="about-tag">🇧🇷 Brasil</span>
      <span class="about-tag"><?= __('about.since') ?></span>
    </div>
  </div>
</section>